import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.C9sp7nFj.js";const _=JSON.parse('{"title":"如何买到便宜机票","description":"低价机票购买技巧和比价平台推荐","frontmatter":{"title":"如何买到便宜机票","description":"低价机票购买技巧和比价平台推荐"},"headers":[],"relativePath":"knowledge/flights/cheap-tickets.md","filePath":"knowledge/flights/cheap-tickets.md","lastUpdated":null}'),i={name:"knowledge/flights/cheap-tickets.md"};function l(n,a,s,h,c,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="如何买到便宜机票" tabindex="-1">如何买到便宜机票 <a class="header-anchor" href="#如何买到便宜机票" aria-label="Permalink to &quot;如何买到便宜机票&quot;">​</a></h1><h2 id="最佳购票时间" tabindex="-1">最佳购票时间 <a class="header-anchor" href="#最佳购票时间" aria-label="Permalink to &quot;最佳购票时间&quot;">​</a></h2><p>国际机票通常提前2-3个月预订价格最优。周二和周三出发的航班往往比周末便宜。</p><h2 id="比价平台推荐" tabindex="-1">比价平台推荐 <a class="header-anchor" href="#比价平台推荐" aria-label="Permalink to &quot;比价平台推荐&quot;">​</a></h2><p>Skyscanner、Google Flights和Kayak等聚合平台可以一次性对比多家航空公司的价格。天巡网（Skyscanner）覆盖最广。</p><h2 id="促销活动提醒" tabindex="-1">促销活动提醒 <a class="header-anchor" href="#促销活动提醒" aria-label="Permalink to &quot;促销活动提醒&quot;">​</a></h2><p>关注航空公司的会员促销和双十一、黑五等购物节的机票折扣。航空公司的会员日通常会有特价票放出。</p><h2 id="里程积分技巧" tabindex="-1">里程积分技巧 <a class="header-anchor" href="#里程积分技巧" aria-label="Permalink to &quot;里程积分技巧&quot;">​</a></h2><p>累积航空里程可以兑换免费机票或升舱。选择合适的常旅客计划和信用卡可以加速积分积累。</p>',9)])])}const k=e(i,[["render",l]]);export{_ as __pageData,k as default};
